function sensoryLevelDescription(level) {
  if ((level <= 2)) { return "Very Low";  }
  if ((level <= 4)) { return "Low";  }
  if ((level <= 6)) { return "Moderate";  }
  if ((level <= 8)) { return "High";  }
  return "Very High";
}

function isValidSensoryLevel(level) {
  return ((level >= 0) && (level <= 10));
}

// type SensoryProfile
function validateSensoryProfile(p) {
  return ((isValidSensoryLevel(p.noise) && isValidSensoryLevel(p.light)) && isValidSensoryLevel(p.crowd));
}

function exceedsProfile(levels, profile) {
  return (((levels.noise > profile.noise) || (levels.light > profile.light)) || (levels.crowd > profile.crowd));
}

