function test_sensory_very_low() {
  const _id3 = assert_eq_str(sensoryLevelDescription(0), "Very Low", "sensoryLevelDescription: 0 -> Very Low");
  const _id4 = assert_eq_str(sensoryLevelDescription(1), "Very Low", "sensoryLevelDescription: 1 -> Very Low");
  const _id5 = assert_eq_str(sensoryLevelDescription(2), "Very Low", "sensoryLevelDescription: 2 -> Very Low");
  return 0;
}

function test_sensory_low() {
  const _id6 = assert_eq_str(sensoryLevelDescription(3), "Low", "sensoryLevelDescription: 3 -> Low");
  const _id7 = assert_eq_str(sensoryLevelDescription(4), "Low", "sensoryLevelDescription: 4 -> Low");
  return 0;
}

function test_sensory_moderate() {
  const _id8 = assert_eq_str(sensoryLevelDescription(5), "Moderate", "sensoryLevelDescription: 5 -> Moderate");
  const _id9 = assert_eq_str(sensoryLevelDescription(6), "Moderate", "sensoryLevelDescription: 6 -> Moderate");
  return 0;
}

function test_sensory_high() {
  const _id10 = assert_eq_str(sensoryLevelDescription(7), "High", "sensoryLevelDescription: 7 -> High");
  const _id11 = assert_eq_str(sensoryLevelDescription(8), "High", "sensoryLevelDescription: 8 -> High");
  return 0;
}

function test_sensory_very_high() {
  const _id12 = assert_eq_str(sensoryLevelDescription(9), "Very High", "sensoryLevelDescription: 9 -> Very High");
  const _id13 = assert_eq_str(sensoryLevelDescription(10), "Very High", "sensoryLevelDescription: 10 -> Very High");
  return 0;
}

function test_valid_level_accepts() {
  const _id14 = assert_true(isValidSensoryLevel(0), "isValidSensoryLevel accepts 0");
  const _id15 = assert_true(isValidSensoryLevel(5), "isValidSensoryLevel accepts 5");
  const _id16 = assert_true(isValidSensoryLevel(10), "isValidSensoryLevel accepts 10");
  return 0;
}

function test_valid_level_rejects_negative() {
  const _id17 = assert_false(isValidSensoryLevel((0 - 1)), "isValidSensoryLevel rejects -1");
  return 0;
}

function test_valid_level_rejects_above_10() {
  const _id18 = assert_false(isValidSensoryLevel(11), "isValidSensoryLevel rejects 11");
  return 0;
}

function test_validate_accepts_valid() {
  const p = ({ noise: 5, light: 6, crowd: 4 });
  const _id19 = assert_true(validateSensoryProfile(p), "validateSensoryProfile accepts {5,6,4}");
  return 0;
}

function test_validate_rejects_invalid_noise() {
  const p = ({ noise: 11, light: 5, crowd: 5 });
  const _id20 = assert_false(validateSensoryProfile(p), "validateSensoryProfile rejects noise=11");
  return 0;
}

function test_validate_rejects_negative_light() {
  const p = ({ noise: 5, light: (0 - 1), crowd: 5 });
  const _id21 = assert_false(validateSensoryProfile(p), "validateSensoryProfile rejects light=-1");
  return 0;
}

function test_exceeds_returns_true_when_exceeded() {
  const levels = ({ noise: 7, light: 6, crowd: 5 });
  const profile = ({ noise: 6, light: 5, crowd: 5 });
  const _id22 = assert_true(exceedsProfile(levels, profile), "exceedsProfile: levels exceed");
  return 0;
}

function test_exceeds_returns_false_when_within() {
  const levels = ({ noise: 5, light: 4, crowd: 3 });
  const profile = ({ noise: 6, light: 5, crowd: 5 });
  const _id23 = assert_false(exceedsProfile(levels, profile), "exceedsProfile: levels within");
  return 0;
}

function test_exceeds_returns_false_when_equal() {
  const levels = ({ noise: 5, light: 5, crowd: 5 });
  const profile = ({ noise: 5, light: 5, crowd: 5 });
  const _id24 = assert_false(exceedsProfile(levels, profile), "exceedsProfile: levels equal profile");
  return 0;
}

function test_exceeds_returns_true_when_any_exceeds() {
  const levels = ({ noise: 4, light: 4, crowd: 6 });
  const profile = ({ noise: 5, light: 5, crowd: 5 });
  const _id25 = assert_true(exceedsProfile(levels, profile), "exceedsProfile: crowd exceeds");
  return 0;
}

